import React, { useState, useRef } from 'react';
import { analyzeImage, ApiError, PredictionResponse } from '../services/api';
import './UploadPage.css';

interface AnalysisResult extends PredictionResponse {
  duration?: number;
}

const UploadPage: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0] || null;
    if (!file) return;

    if (file.size > 10 * 1024 * 1024) {
      setError('File size exceeds 10MB limit');
      return;
    }

    const allowedExtensions = ['jpg','jpeg','png','jfif','gif','bmp','webp','tiff','tif'];
    const fileExtension = file.name.split('.').pop()?.toLowerCase();
    if (!fileExtension || !allowedExtensions.includes(fileExtension)) {
      setError('Invalid file type.');
      return;
    }

    const img = new Image();
    img.onload = () => {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setError(null);
      setResult(null);
    };
    img.onerror = () => setError('Invalid image file.');
    img.src = URL.createObjectURL(file);
  };

  const handleAnalyzeImage = async () => {
    if (!selectedFile) {
      setError('Please select an MRI image.');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);

    const startTime = Date.now();

    try {
      const response = await analyzeImage(selectedFile);
      const duration = (Date.now() - startTime) / 1000;
      setResult({ ...response, duration });
    } catch (err) {
      const apiError = err as ApiError;
      setError(apiError.error || 'Analysis failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleRemoveFile = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setError(null);
    setResult(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const getRiskLevel = (confidence: number): string => {
    if (confidence >= 80) return 'High';
    if (confidence >= 60) return 'Medium';
    return 'Low';
  };

  return (
    <div className="upload-page">
      <div className="upload-container">
        <h1>Brain MRI Analysis</h1>
        <p className="subtitle">AI Powered Clinical Decision Support System</p>

        {/* Upload */}
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          onChange={handleFileChange}
          hidden
        />

        {!selectedFile ? (
          <div className="upload-area" onClick={() => fileInputRef.current?.click()}>
            <div className="upload-icon">🧠</div>
            <h3>Upload MRI Scan</h3>
            <p>Click to browse (Max 10MB)</p>
          </div>
        ) : (
          <div className="file-selected">
            <span>{selectedFile.name}</span>
            <button onClick={handleRemoveFile}>Remove</button>
          </div>
        )}

        {previewUrl && (
          <img src={previewUrl} alt="Preview" className="preview-image" />
        )}

        {selectedFile && !result && (
          <button className="btn-analyze" onClick={handleAnalyzeImage}>
            Analyze Image
          </button>
        )}

        {loading && <div className="loader"></div>}

        {/* RESULTS */}
        {result && (
          <div className="results-section">

            <h2>Analysis Results</h2>

            <div className="result-box">
              <h3>
                {result.prediction === 'tumor'
                  ? '🔴 Brain Tumor Detected'
                  : '🟢 No Tumor Detected'}
              </h3>

              <p className="confidence-score">
                Confidence: {result.confidence.toFixed(1)}%
              </p>

              <p><strong>Risk Level:</strong> {getRiskLevel(result.confidence)}</p>
              <p><strong>Completed In:</strong> {result.duration?.toFixed(2)}s</p>
              <p><strong>Model Version:</strong> {result.model_version}</p>
            </div>

            {/* Emergency Warning */}
            {result.prediction === 'tumor' && result.confidence >= 85 && (
              <div className="emergency-box">
                ⚠️ High Probability Tumor Detection.
                Immediate medical consultation recommended.
              </div>
            )}

            {/* Preliminary Guidance */}
            <div className="medical-guidance">
              <h3>Preliminary Medical Guidance</h3>

              {result.prediction === 'tumor' ? (
                <>
                  <p><strong>Condition:</strong> Brain Tumor (AI Preliminary Detection)</p>
                  <ul>
                    <li>Consult a Neurologist or Neurosurgeon immediately.</li>
                    <li>Recommended: MRI with contrast / CT Scan.</li>
                    <li>Early diagnosis improves treatment outcomes.</li>
                    <li>Avoid stress and follow medical supervision.</li>
                  </ul>
                  <p className="hospital-guide">
                    Visit a multi-specialty hospital with Neurology or Oncology department.
                  </p>
                </>
              ) : (
                <>
                  <p><strong>Status:</strong> No Tumor Detected.</p>
                  <ul>
                    <li>No immediate abnormality detected.</li>
                    <li>Maintain regular health checkups.</li>
                    <li>If symptoms persist, consult a Neurologist.</li>
                  </ul>
                  <p className="hospital-guide">
                    Routine hospital consultation is sufficient.
                  </p>
                </>
              )}
            </div>

            {/* Legal Disclaimer */}
            <div className="disclaimer-box">
              ⚖️ This result is generated by an AI system and is for preliminary
              screening purposes only. It is NOT a confirmed medical diagnosis.
              Please consult a certified medical professional.
            </div>

            {/* Report Button */}
            <button className="report-btn">
              📄 Download Medical Report (PDF)
            </button>

          </div>
        )}

        {error && <div className="error-box">{error}</div>}
      </div>
    </div>
  );
};

export default UploadPage;
